import type { Menu, MenuWithItems, MenuItemCreate, MenuCreate } from "@/types"

const BASE =
  process.env.NEXT_PUBLIC_API_BASE_URL || "http://localhost:4000/api";

async function json<T>(res: Response): Promise<T> {
  if (!res.ok) {
    const text = await res.text().catch(() => "");
    throw new Error(text || `Request failed with ${res.status}`);
  }
  return (await res.json()) as T;
}

export async function getMenus(): Promise<Menu[]> {
  const res = await fetch(`${BASE}/menus`, { cache: "no-store" });
  return json<Menu[]>(res);
}

export async function createMenu(payload: MenuCreate): Promise<Menu> {
  const res = await fetch(`${BASE}/menus`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(payload),
  });
  return json<Menu>(res);
}

export async function getMenuById(id: string): Promise<MenuWithItems> {
  const res = await fetch(`${BASE}/menus/${id}`, { cache: "no-store" });
  return json<MenuWithItems>(res);
}

export async function addItem(
  menuId: string,
  payload: MenuItemCreate
): Promise<{ success: boolean }> {
  const res = await fetch(`${BASE}/menus/${menuId}/items`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(payload),
  });
  return json<{ success: boolean }>(res);
}
