"use client";

import Link from "next/link";
import { useEffect, useState } from "react";

import type { Menu } from "@/types";
import { getMenus } from "@/services/api";

export default function HomePage() {
  const [menus, setMenus] = useState<Menu[]>([]);
  const [loading, setLoading] = useState(true);
  const [err, setErr] = useState<string | null>(null);

  useEffect(() => {
    (async () => {
      try {
        const data = await getMenus();
        setMenus(data || []);
      } catch (e: any) {
        setErr("Failed to load menus");
      } finally {
        setLoading(false);
      }
    })();
  }, []);

  if (loading) return <p>Loading menus…</p>;
  if (err) return <p className="text-red-600">{err}</p>;

  return (
    <main>
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-semibold">Menus</h1>
        <Link
          href="/menu/new"
          className="inline-block rounded bg-blue-600 px-4 py-2 text-white"
        >
          + Add Menu
        </Link>
      </div>

      <ul className="mt-4 grid gap-3 md:grid-cols-2">
        {menus.length === 0 && (
          <li className="rounded border p-4">No menus yet.</li>
        )}
        {menus.map((m) => (
          <li key={m._id} className="rounded border p-4 hover:bg-neutral-100">
            <Link href={`/menu/${m._id}`} className="block">
              <div className="flex items-center justify-between">
                <h2 className="font-medium">{m.name}</h2>
              </div>
              {m.description ? (
                <p className="text-sm text-neutral-600 mt-1">{m.description}</p>
              ) : null}
            </Link>
          </li>
        ))}
      </ul>
    </main>
  );
}
